import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic3x3() {
        int[][] matrix = {{1,2,3},{4,5,6},{7,8,9}};
        assertArrayEquals(new int[]{1,2,4,7,5,3,6,8,9}, new Solution().diagonalOrder(matrix));
    }

    @Test
    void rectangularThreeByTwo() {
        // 3 rows, 2 cols — non-square
        // d=0(even):[1], d=1(odd):[2,3], d=2(even):[5,4], d=3(odd):[6]
        int[][] matrix = {{1,2},{3,4},{5,6}};
        assertArrayEquals(new int[]{1,2,3,5,4,6}, new Solution().diagonalOrder(matrix));
    }

    @Test
    void singleRow() {
        int[][] matrix = {{1, 2, 3}};
        // Only one anti-diagonal per element since m=1; d=0 → {1}, d=1 → {2}, d=2 → {3}
        // Even d=0: up-right → [1], odd d=1: down-left → [2], even d=2: up-right → [3]
        assertArrayEquals(new int[]{1, 2, 3}, new Solution().diagonalOrder(matrix));
    }

    @Test
    void singleColumn() {
        int[][] matrix = {{1},{2},{3}};
        assertArrayEquals(new int[]{1, 2, 3}, new Solution().diagonalOrder(matrix));
    }

    @Test
    void singleCell() {
        int[][] matrix = {{42}};
        assertArrayEquals(new int[]{42}, new Solution().diagonalOrder(matrix));
    }

    @Test
    void emptyMatrix() {
        int[][] matrix = {};
        assertArrayEquals(new int[]{}, new Solution().diagonalOrder(matrix));
    }

    @Test
    void twoByThree() {
        // 2 rows, 3 cols
        // d=0(even):[1], d=1(odd,i=0→2,i=1→4):[2,4], d=2(even,i=1→5,i=0→3):[5,3], d=3(odd):[6]
        int[][] matrix = {{1,2,3},{4,5,6}};
        assertArrayEquals(new int[]{1,2,4,5,3,6}, new Solution().diagonalOrder(matrix));
    }
}
